import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";const i=JSON.parse(`{"title":"Absturzberichte","description":"Erfahre, wie mit Absturzberichten umzugehen ist, und wie man sie liest.","frontmatter":{"title":"Absturzberichte","description":"Erfahre, wie mit Absturzberichten umzugehen ist, und wie man sie liest.","authors":["IMB11"],"search":false,"files":[]},"headers":[],"relativePath":"de_de/1.20.4/players/troubleshooting/crash-reports.md","filePath":"versions/1.20.4/translated/de_de/players/troubleshooting/crash-reports.md","lastUpdated":1766341111000}`);var a={name:`de_de/1.20.4/players/troubleshooting/crash-reports.md`};function o(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Absturzberichte <a class="header-anchor" href="#h1" aria-label="Permalink to “Absturzberichte”">​</a></h1><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>Falls du Schwierigkeiten hast, den Grund für einen Absturz herauszufinden, frage im <a href="https://discord.gg/v6v4pMv" target="_blank" rel="noreferrer">Fabric Discord</a> im Kanal <code>#player-support</code> oder <code>#server-admin-support</code> nach Hilfe.</p></div><p>Absturzberichte sind ein sehr wichtiger Teil, um Probleme mit deinem Spiel oder Server zu beheben. Sie enthalten viele Informationen über den Absturz und können beim Finden der Ursache für den Absturz hilfreich sein.</p><h2 id="absturzberichte-finden" tabindex="-1">Absturzberichte finden <a class="header-anchor" href="#absturzberichte-finden" aria-label="Permalink to “Absturzberichte finden”">​</a></h2><p>Absturzberichte werden im <code>crash-reports</code>-Verzeichnis in deinem Spiel-Verzeichnis gespeichert. Falls du einen Server nutzt, sind sie im <code>crash-reports</code>-Verzeichnis im Server-Verzeichnis.</p><p>Für Launcher von Drittanbietern solltest du deren Dokumentation verwenden, um den Ort der Absturzberichte zu finden.</p><p>Absturzberichte befinden sich an den folgenden Orten:</p><div class="vp-code-group"><div class="tabs"><input type="radio" name="group-23" id="tab-24" checked><label data-title="Windows" for="tab-24">Windows</label><input type="radio" name="group-23" id="tab-25"><label data-title="macOS" for="tab-25">macOS</label><input type="radio" name="group-23" id="tab-26"><label data-title="Linux" for="tab-26">Linux</label></div><div class="blocks"><div class="language- active"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>%appdata%\\.minecraft\\crash-reports</span></span></code></pre></div><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>~/Library/Application Support/minecraft/crash-reports</span></span></code></pre></div><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>~/.minecraft/crash-reports</span></span></code></pre></div></div></div><h2 id="absturzberichte-lesen" tabindex="-1">Absturzberichte lesen <a class="header-anchor" href="#absturzberichte-lesen" aria-label="Permalink to “Absturzberichte lesen”">​</a></h2><p>Absturzberichte sind sehr lang und können verwirrend zu lesen sein. Allerdings enthalten sie viele Informationen über den Absturz, die beim Finden der Ursache sehr hilfreich sind.</p><p>In dieser Anleitung werden wir den <a href="https://github.com/FabricMC/fabric-docs/blob/main/public/assets/players/crash-report-example.log" target="_blank" rel="noreferrer">folgenden Absturzbericht als Beispiel</a> verwenden.</p><h3 id="abschnitte-des-absturzberichts" tabindex="-1">Abschnitte des Absturzberichts <a class="header-anchor" href="#abschnitte-des-absturzberichts" aria-label="Permalink to “Abschnitte des Absturzberichts”">​</a></h3><p>Absturzberichte bestehen aus mehreren Abschnitten, jeder ist mit einer Überschrift getrennt:</p><ul><li><code>---- Minecraft Crash Report ----</code>, die Zusammenfassung des Berichts. Dieser Abschnitt enthält den Hauptfehler, der den Absturz verursacht hat, den Zeitpunkt an dem das Problem aufgetreten ist und den relevanten Stacktrace. Dies ist der wichtigste Abschnitt des Absturzberichts, da der Stacktrace normalerweise Referenzen zu der Mod enthält, die den Absturz verursacht hat.</li><li><code>-- Last Reload --</code>, dieser Abschnitt ist nicht wirklich hilfreich, es sei denn, der Absturz ist während dem Neu-Laden von Resourcen (<kbd>F3</kbd>+<kbd>T</kbd>) aufgetreten. Dieser Abschnitt enthält den Zeitpunkt des letzten Neu-Ladens, den relevanten Stacktrace und alle Fehler, die währenddessen aufgetreten sind. Diese Fehler werden normalerweise durch Ressourcenpakete ausgelöst und können ignoriert werden, wenn sie keine Probleme mit dem Spiel verursachen.</li><li><code>-- System Details --</code>, dieser Abschnitt enthält Informationen über dein System, wie das Betriebssystem, die Java-Version, und die Speichermenge, die dem Spiel zugewiesen wurde. Dieser Abschnitt ist nützlich, um festzustellen, ob du die korrekte Java-Version verwendest und ob du dem Spiel genug Speicher zugewiesen hast. <ul><li>In diesem Abschnitt fügt Fabric eine eigene Zeile ein, die mit <code>Fabric Mods:</code> beginnt und darauf folgend alle installierten Mods auflistet. Dieser Abschnitt ist nützlich, um festzustellen, ob Konflikte zwischen Mods aufgetreten sein könnten.</li></ul></li></ul><h3 id="den-absturzbericht-herunterbrechen" tabindex="-1">Den Absturzbericht herunterbrechen <a class="header-anchor" href="#den-absturzbericht-herunterbrechen" aria-label="Permalink to “Den Absturzbericht herunterbrechen”">​</a></h3><p>Da wir jetzt alle Abschnitte des Absturzberichts kennengelernt haben, können wir nun beginnen, den Absturzbericht herunterzubrechen und die Ursache des Absturzes zu finden.</p><p>Mit dem obigen verwiesenen Beispiel können wir den Absturzbericht analysieren und die Ursache für den Absturz herausfinden und welche Mods den Absturz verursachen.</p><p>Der Stacktrace im <code>---- Minecraft Crash Report ----</code>-Abschnitt ist in diesem Fall der wichtigste, da er den Hauptfehler, der diesen Absturz verursacht, enthält. In diesem Fall ist der Fehler <code>java.lang.NullPointerException: Cannot invoke &quot;net.minecraft.class_2248.method_9539()&quot; because &quot;net.minecraft.class_2248.field_10540&quot; is null</code>.</p><p>Mit der Anzahl an Mods, die sich in diesem Stacktrace befinden, kann es schwierig sein, den Schuldigen zu finden, aber das Erste, was zu tun ist, ist die Mod zu finden, die den Absturz verursacht.</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>at snownee.snow.block.ShapeCaches.get(ShapeCaches.java:51)</span></span>
<span class="line"><span>at snownee.snow.block.SnowWallBlock.method_9549(SnowWallBlock.java:26) // [!code focus]</span></span>
<span class="line"><span>...</span></span>
<span class="line"><span>at me.jellysquid.mods.sodium.client.render.chunk.compile.pipeline.BlockOcclusionCache.shouldDrawSide(BlockOcclusionCache.java:52)</span></span>
<span class="line"><span>at link.infra.indium.renderer.render.TerrainBlockRenderInfo.shouldDrawFaceInner(TerrainBlockRenderInfo.java:31)</span></span>
<span class="line"><span>...</span></span></code></pre></div><p>In diesem Fall ist die Mod, die den Absturz verursacht <code>snownee</code>, da es die erste Mod im Stacktrace ist, die erwähnt wird.</p><p>Mit der Anzahl an erwähnten Mods kann es aber auf Kompatibilitätsprobleme zwischen den Mods hindeuten, und die Mod, die den Absturz verursacht hat, muss nicht die Schuldige sein. In diesem Fall ist es das Beste, den Absturz dem Autor zu melden und ihn den Absturz weiter untersuchen zu lassen.</p><h2 id="absturze-durch-mixins" tabindex="-1">Abstürze durch Mixins <a class="header-anchor" href="#absturze-durch-mixins" aria-label="Permalink to “Abstürze durch Mixins”">​</a></h2><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p>Mixins sind eine Möglichkeit, das Spiel zu verändern, ohne den Quellcode des Spiels zu verändern. Sie werden von vielen Mods genutzt und sind ein mächtiges Werkzeug für Mod-Entwickler.</p></div><p>Wenn ein Mixin abstürzt, wird normalerweise das Mixin im Stacktrace erwähnt, mit der Klasse, die das Mixin verändert.</p><p>Mixins für Methoden enthalten <code>mod-id$handlerName</code> im Stacktrace, wobei <code>mod-id</code> die ID der Mod ist und <code>handlerName</code> der Name des Mixin-Handlers ist.</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>... net.minecraft.class_2248.method_3821$$$mod-id$handlerName() ... // [!code focus]</span></span></code></pre></div><p>Du kannst diese Information nutzen, um die Mod zu finden, die den Absturz verursacht und den Absturz an den Mod-Autor zu melden.</p><h2 id="was-macht-man-mit-absturzberichten" tabindex="-1">Was macht man mit Absturzberichten <a class="header-anchor" href="#was-macht-man-mit-absturzberichten" aria-label="Permalink to “Was macht man mit Absturzberichten”">​</a></h2><p>Das Beste, was man mit Absturzberichten machen kann, ist sie auf eine Paste-Seite hochzuladen und einen Link mit dem Mod-Autor entweder über den Issue-Tracker oder durch eine andere Art der Kommunikation (Discord etc.) zu teilen.</p><p>Das ermöglicht es dem Mod-Autor den Absturz zu untersuchen, potenziell zu reproduzieren und das Problem zu lösen, das den Absturz verursacht hat.</p><p>Bekannte Paste-Seiten, die oft für Absturzberichte genutzt werden, sind:</p><ul><li><a href="https://gist.github.com/" target="_blank" rel="noreferrer">GitHub Gist</a></li><li><a href="https://pastebin.com/" target="_blank" rel="noreferrer">Pastebin</a></li><li><a href="https://mclo.gs/" target="_blank" rel="noreferrer">MCLogs</a></li></ul>`,33)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};